        elif event.type == "response.websearchcall.completed":
            print("✅ 搜索完成")
        elif event.type == "response.output_text.delta":
            print(event.delta, end="", flush=True)

responseswithwebsearchstream()
```

4. Vertex AI API (Google 兼容)

Vertex AI API 使用 `tools` 参数中的 `googleSearch` 启用 Google Search Grounding 功能。

参数说明

在 Vertex AI 中，Web Search 通过 `googleSearch` 工具启用，并通过响应中的 `groundingMetadata` 返回搜索来源信息。

| 参数                   | 类型   | 必填 | 说明                                 |
| ---------------------- | ------ | ---- | ------------------------------------ |
| `tools[].googleSearch` | object | 是   | Google Search 配置（空对象即可启用） |

响应中的 Grounding 信息

| 字段                                             | 类型   | 说明           |
| ------------------------------------------------ | ------ | -------------- |
| `groundingMetadata.webSearchQueries`             | array  | 执行的搜索查询 |
| `groundingMetadata.groundingChunks`              | array  | 证据片段       |
| `groundingMetadata.groundingChunks[].web.uri`    | string | 来源 URL       |
| `groundingMetadata.groundingChunks[].web.title`  | string | 来源标题       |
| `groundingMetadata.groundingChunks[].web.domain` | string | 来源域名       |

示例

```typescript
import { GoogleGenAI } from "@google/genai";

// 使用 ShuYou 代理
const client = new GoogleGenAI({
  apiKey: "YOURAPIKEY",
  vertexai: true,
  httpOptions: {
    baseUrl: "https://api.shuyou.ai",
    apiVersion: "v1",
  },
});

async function generateWithGoogleSearch() {
  const response = await client.models.generateContent({
    model: "google/gemini-2.0-flash",
    contents: "请告诉我今天的科技新闻头条",
    config: {
      tools: [{ googleSearch: {} }],
      temperature: 0.7,
      maxOutputTokens: 2048,
    },
  });

  // 获取生成的文本
  console.log("回答:", response.text);

  // 获取 Grounding 信息
  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  if (groundingMetadata) {
    console.log("\n搜索查询:", groundingMetadata.webSearchQueries);

    if (groundingMetadata.groundingChunks) {
      console.log("\n引用来源:");
      groundingMetadata.groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          console.log(`- ${chunk.web.title}: ${chunk.web.uri}`);
        }
      });
    }
  }
}

// 流式请求
async function generateWithGoogleSearchStream() {
  const response = await client.models.generateContentStream({
    model: "google/gemini-2.0-flash",
    contents: "最近有什么重要的AI领域进展？",
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  console.log("回答:");
  for await (const chunk of response) {
    if (chunk.text) {
      process.stdout.write(chunk.text);
    }

    // 最后一个 chunk 可能包含 groundingMetadata
    const groundingMetadata = chunk.candidates?.[0]?.groundingMetadata;
    if (groundingMetadata?.groundingChunks) {
      console.log("\n\n引用来源:");
      groundingMetadata.groundingChunks.forEach((c: any) => {
        if (c.web) {
          console.log(`- ${c.web.title}: ${c.web.uri}`);
        }
      });
    }
  }
}

generateWithGoogleSearch();
```

```python
from google import genai
from google.genai import types

配置使用 ShuYou 代理
client = genai.Client(
    apikey="YOURAPI_KEY",
    vertexai=True,
    http_options=types.HttpOptions(
        api_version='v1',
        base_url='https://api.shuyou.ai'
    ),
)

非流式请求
def generatewithgoogle_search():
    response = client.models.generate_content(
        model="google/gemini-2.0-flash",
        contents="请告诉我今天的科技新闻头条",
        config=types.GenerateContentConfig(
            tools=[types.Tool(google_search=types.GoogleSearch())],
            temperature=0.7,
            maxoutputtokens=2048
        )
    )

    # 获取生成的文本
    print("回答:", response.text)

    # 获取 Grounding 信息
    if response.candidates and response.candidates[0].grounding_metadata:
        metadata = response.candidates[0].grounding_metadata

        if metadata.websearchqueries:
            print("\n搜索查询:", metadata.websearchqueries)

        if metadata.grounding_chunks:
            print("\n引用来源:")
            for chunk in metadata.grounding_chunks:
                if chunk.web:
                    print(f"- {chunk.web.title}: {chunk.web.uri}")

流式请求
def generatewithgooglesearchstream():
    response = client.models.generatecontentstream(
        model="google/gemini-2.0-flash",
        contents="最近有什么重要的AI领域进展？",
        config=types.GenerateContentConfig(
            tools=[types.Tool(google_search=types.GoogleSearch())]
        )
    )

    print("回答:")
    for chunk in response:
        if chunk.text:
            print(chunk.text, end="", flush=True)

        # 最后一个 chunk 可能包含 grounding_metadata
        if chunk.candidates and chunk.candidates[0].grounding_metadata:
            metadata = chunk.candidates[0].grounding_metadata
            if metadata.grounding_chunks:
                print("\n\n引用来源:")
                for c in metadata.grounding_chunks:
                    if c.web:
                        print(f"- {c.web.title}: {c.web.uri}")

generatewithgoogle_search()
```

响应格式对比

Chat Completions 响应

```json
{
  "choices": [
    {
      "message": {
        "role": "assistant",
        "content": "根据搜索结果...",
        "annotations": [
          {
            "type": "url_citation",
            "url_citation": {
              "title": "来源标题",
              "url": "https://example.com/article",
              "start_index": 0,
              "end_index": 0
            }
          }
        ]
      }
    }
  ]
}
```

Messages 响应

```json
{
  "content": [
    {
      "type": "text",
      "text": "根据搜索结果..."
    },
    {
      "type": "websearchtool_result",
      "tooluseid": "...",
      "content": [
        {
          "type": "websearchresult",
          "title": "来源标题",
          "url": "https://example.com/article"
        }
      ]
    }
  ],
  "usage": {
    "input_tokens": 100,
    "output_tokens": 200,
    "servertooluse": {
      "websearchrequests": 2
    }
  }
}
```

