    {
      "type": "websearchcall",
      "id": "ws_...",
      "status": "completed"
    },
    {
      "type": "message",
      "content": [
        {
          "type": "output_text",
          "text": "根据搜索结果...",
          "annotations": [
            {
              "type": "url_citation",
              "url_citation": {
                "title": "来源标题",
                "url": "https://example.com/article"
              }
