OpenAI Responses API

OpenAI Responses API 提供了更现代化的工具调用接口，工具定义方式与 Chat Completion API 类似，但响应结构有所不同。

工具定义

Responses API 中的工具定义使用 `tools` 参数，支持函数工具、内置工具和 MCP 工具：

```json
{
  "tools": [
    {
      "type": "function",
      "name": "get_weather",
      "description": "获取给定位置的当前天气",
      "parameters": {
        "type": "object",
        "properties": {
          "location": {
            "type": "string",
            "description": "城市名称，如 北京"
          }
        },
        "required": ["location"]
      }
    }
  ]
}
```

完整示例

```python [Python]
from openai import OpenAI
import json

client = OpenAI(
    base_url="https://api.shuyou.ai/v1",
    api_key="",
)

定义工具
tools = [
    {
        "type": "function",
        "name": "get_weather",
        "description": "获取给定位置的当前天气",
        "parameters": {
            "type": "object",
            "properties": {
                "location": {
                    "type": "string",
                    "description": "城市名称"
                }
            },
            "required": ["location"]
        }
    }
]

1. 发送请求
response = client.responses.create(
    model="openai/gpt-5", # [!code highlight]
    input="北京今天的天气怎么样？",
    tools=tools
)

2. 检查是否有工具调用
function_calls = []
for item in response.output:
    if item.type == "function_call":
        function_calls.append(item)

if function_calls:
    # 3. 执行工具调用
    def get_weather(location):
        return {"temperature": "25°C", "condition": "晴朗"}

    tool_outputs = []
    for call in function_calls:
        args = json.loads(call.arguments)
        result = get_weather(args["location"])
        tool_outputs.append({
            "type": "functioncalloutput",
            "callid": call.callid,
            "output": json.dumps(result, ensure_ascii=False)
        })

    # 4. 将工具结果发送回模型
    final_response = client.responses.create(
        model="openai/gpt-5",
        input=tool_outputs,
        previousresponseid=response.id
    )

    # 提取最终回答
    for item in final_response.output:
        if item.type == "message":
            for content in item.content:
                if content.type == "output_text":
                    print(content.text)
```

```typescript [TypeScript]
import OpenAI from "openai";

const client = new OpenAI({
  baseURL: "https://api.shuyou.ai/v1",
  apiKey: "",
});

// 定义工具
const tools = [
  {
    type: "function" as const,
    name: "get_weather",
    description: "获取给定位置的当前天气",
    parameters: {
      type: "object",
      properties: {
        location: {
          type: "string",
          description: "城市名称",
        },
      },
      required: ["location"],
    },
  },
];

async function main() {
  // 1. 发送请求
  const response = await client.responses.create({
    model: "openai/gpt-5", // [!code highlight]
    input: "北京今天的天气怎么样？",
    tools,
  });

  // 2. 检查是否有工具调用
  const functionCalls = response.output.filter(
    (item) => item.type === "function_call",
  );

  if (functionCalls.length > 0) {
    // 3. 执行工具调用
    function getWeather(location: string) {
      return { temperature: "25°C", condition: "晴朗" };
    }

    const toolOutputs = functionCalls.map((call) => ({
      type: "functioncalloutput" as const,
      callid: call.callid,
      output: JSON.stringify(getWeather(JSON.parse(call.arguments).location)),
    }));

    // 4. 将工具结果发送回模型
    const finalResponse = await client.responses.create({
      model: "openai/gpt-5",
      input: toolOutputs,
      previousresponseid: response.id,
    });

    // 提取最终回答
    for (const item of finalResponse.output) {
      if (item.type === "message") {
        for (const content of item.content) {
          if (content.type === "output_text") {
            console.log(content.text);
          }
        }
      }
    }
  }
}

main();
```

