tool_choice 参数

与 Chat Completion API 类似，Responses API 也支持 `tool_choice` 参数：

- `"auto"`：（默认）模型自动决定是否调用工具
- `"required"`：强制模型调用至少一个工具
- `"none"`：禁止调用工具
- `{"type": "function", "name": "xxx"}`：强制调用指定工具

Anthropic Messages API

Anthropic Claude 模型通过 `tools` 参数支持工具调用功能。工具定义使用 `input_schema` 字段而非 `parameters`。

工具定义

Anthropic 的工具定义格式：

```json
{
  "tools": [
    {
      "name": "get_weather",
      "description": "获取给定位置的当前天气",
      "input_schema": {
        "type": "object",
        "properties": {
          "location": {
            "type": "string",
            "description": "城市名称，如 北京"
          }
        },
        "required": ["location"]
      }
    }
  ]
}
```

Anthropic 支持 `strict: true` 参数启用严格模式，确保工具调用参数始终符合 schema 定义。

完整示例

```python [Python]
import anthropic
import json

client = anthropic.Anthropic(
    api_key="", # [!code highlight]
    base_url="https://shuyou.ai" # [!code highlight]
)

定义工具
tools = [
    {
        "name": "get_weather",
        "description": "获取给定位置的当前天气。用户询问天气时调用此工具。",
        "input_schema": {
            "type": "object",
            "properties": {
                "location": {
                    "type": "string",
                    "description": "城市名称，如 北京、上海"
                }
            },
            "required": ["location"]
        }
    }
]

1. 发送请求
message = client.messages.create(
    model="anthropic/claude-sonnet-4.5", # [!code highlight]
    max_tokens=1024,
    tools=tools,
    messages=[
        {"role": "user", "content": "北京今天的天气怎么样？"}
    ]
)

2. 检查是否需要工具调用
if message.stopreason == "tooluse":
    # 提取工具调用
    tooluseblock = None
    for block in message.content:
        if block.type == "tool_use":
            tooluseblock = block
            break

    if tooluseblock:
        # 3. 执行工具调用
        def get_weather(location):
            return {"temperature": "25°C", "condition": "晴朗", "humidity": "40%"}

        result = getweather(tooluse_block.input["location"])

        # 4. 将工具结果发送回模型
        final_message = client.messages.create(
            model="anthropic/claude-sonnet-4.5",
            max_tokens=1024,
            tools=tools,
            messages=[
                {"role": "user", "content": "北京今天的天气怎么样？"},
                {"role": "assistant", "content": message.content},
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "tool_result",
                            "tooluseid": tooluseblock.id,
                            "content": json.dumps(result, ensure_ascii=False)
                        }
                    ]
                }
            ]
        )

        # 提取最终回答
        for block in final_message.content:
            if hasattr(block, "text"):
                print(block.text)
else:
    # 直接输出回答
    for block in message.content:
        if hasattr(block, "text"):
            print(block.text)
```

```typescript [TypeScript]
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({
  apiKey: "", // [!code highlight]
  baseURL: "https://shuyou.ai", // [!code highlight]
});

// 定义工具
const tools: Anthropic.Messages.Tool[] = [
  {
    name: "get_weather",
    description: "获取给定位置的当前天气。用户询问天气时调用此工具。",
    input_schema: {
      type: "object" as const,
      properties: {
        location: {
          type: "string",
          description: "城市名称，如 北京、上海",
        },
      },
      required: ["location"],
    },
  },
];

async function main() {
  // 1. 发送请求
  const message = await client.messages.create({
    model: "anthropic/claude-sonnet-4.5", // [!code highlight]
    max_tokens: 1024,
    tools,
    messages: [{ role: "user", content: "北京今天的天气怎么样？" }],
  });

  // 2. 检查是否需要工具调用
  if (message.stopreason === "tooluse") {
    const toolUseBlock = message.content.find(
      (block) => block.type === "tool_use",
    );

    if (toolUseBlock && toolUseBlock.type === "tool_use") {
      // 3. 执行工具调用
      function getWeather(location: string) {
        return { temperature: "25°C", condition: "晴朗", humidity: "40%" };
      }

      const result = getWeather((toolUseBlock.input as any).location);

      // 4. 将工具结果发送回模型
      const finalMessage = await client.messages.create({
        model: "anthropic/claude-sonnet-4.5",
        max_tokens: 1024,
        tools,
        messages: [
          { role: "user", content: "北京今天的天气怎么样？" },
          { role: "assistant", content: message.content },
          {
            role: "user",
            content: [
              {
                type: "tool_result",
                tooluseid: toolUseBlock.id,
                content: JSON.stringify(result),
              },
            ],
          },
        ],
      });

      // 提取最终回答
      for (const block of finalMessage.content) {
        if (block.type === "text") {
          console.log(block.text);
        }
      }
    }
  } else {
    // 直接输出回答
    for (const block of message.content) {
      if (block.type === "text") {
        console.log(block.text);
      }
    }
  }
}

main();
```

