方式二：工具调用（Tool Use）

通过定义一个工具并强制模型调用它，也可以获得符合指定 JSON Schema 的结构化数据。

实现原理

1. 定义一个工具，其 `input_schema` 描述你期望的输出结构
2. 设置 `tool_choice` 为 `{"type": "tool", "name": "工具名"}` 强制模型调用该工具
3. 从返回的 `tool_use` 内容块中提取结构化数据

```python [Python]
import anthropic

1. 初始化 Anthropic 客户端
client = anthropic.Anthropic(
    # 2. 替换为你从 ShuYou 用户控制台获取的 API Key
    api_key="", # [!code highlight]
    # 3. 将基础 URL 指向 ShuYou 端点
    base_url="https://shuyou.ai" # [!code highlight]
)

4. 定义工具来描述期望的输出结构
tools = [
    {
        "name": "introduce_yourself", # [!code highlight]
        "description": "Introduce yourself with structured information",
        "strict": True, # 启用严格模式，保证参数类型正确
        "input_schema": { # [!code highlight]
            "type": "object",
            "properties": {
                "name": {
                    "type": "string",
                    "description": "your name"
                },
                "city": {
                    "type": "string",
                    "description": "where your city"
                },
                "desc": {
                    "type": "string",
                    "description": "description about yourself"
                }
            },
            "required": ["name", "city", "desc"],
            "additionalProperties": False
        }
    }
]

5. 发起请求，强制调用工具
message = client.messages.create(
    model="anthropic/claude-sonnet-4.5", # [!code highlight]
    max_tokens=1024,
    tools=tools,
    toolchoice={"type": "tool", "name": "introduceyourself"}, # [!code highlight]
    messages=[
        {
            "role": "user",
            "content": "Hi, who are you? Describe yourself using about 50 words."
        }
    ]
)

6. 提取结构化输出
for block in message.content:
    if block.type == "tool_use":
        print(block.input)  # 结构化 JSON 数据
```

```ts [TypeScript]
import Anthropic from "@anthropic-ai/sdk";

// 1. 初始化 Anthropic 客户端
const anthropic = new Anthropic({
  // 2. 替换为你从 ShuYou 用户控制台获取的 API Key
  apiKey: "", // [!code highlight]
  // 3. 将基础 URL 指向 ShuYou 端点
  baseURL: "https://shuyou.ai", // [!code highlight]
});

async function main() {
  // 4. 定义工具来描述期望的输出结构
  const tools = [
    {
      name: "introduce_yourself", // [!code highlight]
      description: "Introduce yourself with structured information",
      strict: true, // 启用严格模式，保证参数类型正确
      input_schema: {
        // [!code highlight]
        type: "object" as const,
        properties: {
          name: {
            type: "string",
            description: "your name",
          },
          city: {
            type: "string",
            description: "where your city",
          },
          desc: {
            type: "string",
            description: "description about yourself",
          },
        },
        required: ["name", "city", "desc"],
        additionalProperties: false,
      },
    },
  ];

  // 5. 发起请求，强制调用工具
  const message = await anthropic.messages.create({
    model: "anthropic/claude-sonnet-4.5", // [!code highlight]
    max_tokens: 1024,
    tools: tools,
    toolchoice: { type: "tool", name: "introduceyourself" }, // [!code highlight]
    messages: [
      {
        role: "user",
        content: "Hi, who are you? Describe yourself using about 50 words.",
      },
    ],
  });

  // 6. 提取结构化输出
  for (const block of message.content) {
    if (block.type === "tool_use") {
      console.log(block.input); // 结构化 JSON 数据
    }
  }
}

main();
```

